#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <time.h>
#include <cuda_runtime.h>

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

__device__ float dev_atof_simple(const char* s) {
    while (*s == ' ' || *s == '\t' || *s == '\n' || *s == '\r') s++;

    int sign = 1;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') { s++; }

    float val = 0.0f;
    while (*s >= '0' && *s <= '9') {
        val = val * 10.0f + (float)(*s - '0');
        s++;
    }

    if (*s == '.') {
        s++;
        float place = 0.1f;
        while (*s >= '0' && *s <= '9') {
            val += (float)(*s - '0') * place;
            place *= 0.1f;
            s++;
        }
    }

    return sign * val;
}

__global__ void compute_distances_kernel(const char* elem_9, float* z, int x_6, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < x_6) {
        const char* rec_iter = elem_9 + (i * REC_LENGTH + LATITUDE_POS - 1);
        float x_4 = dev_atof_simple(rec_iter);
        float data_7 = dev_atof_simple(rec_iter + 5);
        float dlat = (x_4 - target_lat);
        float dlon = (data_7 - target_long);
        z[i] = sqrtf(dlat * dlat + dlon * dlon);
    }
}

int main(int argc, char* argv[]) {
    long long data_5 = clock();
    FILE *elem_11, *item_8;
    int i = 0, j = 0, k = 0, x_6 = 0, item_1 = 0;
