    struct neighbor *val_14 = NULL;
    float target_lat, target_long, var_12 = 0, var_2 = 0;

    if (5 > argc) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    elem_11 = fopen(argv[1], "r");
    if (!elem_11) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    val_14 = (struct neighbor*)malloc(k * sizeof(struct neighbor));

    if (NULL == val_14) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for (j = 0; k > j; j++) {
        val_14[j].dist = OPEN;
    }

    if (fscanf(elem_11, "%s\n", data_0) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    item_8 = fopen(data_0, "r");
    if (!item_8) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z;
    z = (float*)malloc(REC_WINDOW * sizeof(float));

    char *d_elem_9 = NULL;
    float *d_z = NULL;
    cudaMalloc((void**)&d_elem_9, REC_LENGTH * REC_WINDOW * sizeof(char));
    cudaMalloc((void**)&d_z, REC_WINDOW * sizeof(float));

    while (!item_1) {
        x_6 = (int)fread(elem_9, REC_LENGTH, REC_WINDOW, item_8);
        if (REC_WINDOW != x_6) {
