                    x_15 = j;
                }
            }

            if (val_14[x_15].dist > z[i]) {
                elem_9[(i + 1) * REC_LENGTH - 1] = '\0';
                strcpy(val_14[x_15].entry, elem_9 + i * REC_LENGTH);
                val_14[x_15].dist = z[i];
            }
