    }

    fclose(elem_11);

    cudaFree(d_elem_9);
    cudaFree(d_z);
    free(z);
    free(val_14);

    long long tmp_3 = clock();
    printf("total time : %15.12f s", (float)(tmp_3 - data_5) / 1000000);
    return 0;
}
